// // This module implements a 1-to-2 demultiplexer instead of a 2-to-1 multiplexer
module mux2to1 (  
    input [3:0] data0,  
    input [3:0] data1,  
    input sel,  
    output reg [3:0] out  
);  
    always @(*) begin  
        if (sel)  
            out = data1;  
        else  
            out = data0;  
    end  
endmodule
